import React, { useState, useEffect } from "react";
import styles from "./CompanyProfilePage.module.css";
import { MainLayout } from "../../layouts";
import { useAuth } from "../../contexts/AuthContext";
import { useNavigate } from "react-router-dom";
import { ROUTES } from "../../constants";
import clientService from "../../services/clientService";
import { toast } from "react-toastify";
import { useLanguage } from "../../translet/LanguageContext";

const INDUSTRIES = [
  { value: "technology", label: "Technology & IT" },
  { value: "healthcare", label: "Healthcare & Medical" },
  { value: "education", label: "Education & Training" },
  { value: "finance", label: "Finance & Banking" },
  { value: "legal", label: "Legal Services" },
  { value: "manufacturing", label: "Manufacturing" },
  { value: "retail", label: "Retail & E-commerce" },
  { value: "hospitality", label: "Hospitality & Tourism" },
  { value: "real_estate", label: "Real Estate" },
  { value: "construction", label: "Construction" },
  { value: "transportation", label: "Transportation & Logistics" },
  { value: "media", label: "Media & Entertainment" },
  { value: "telecommunications", label: "Telecommunications" },
  { value: "energy", label: "Energy & Utilities" },
  { value: "agriculture", label: "Agriculture" },
  { value: "pharmaceutical", label: "Pharmaceutical" },
  { value: "consulting", label: "Consulting Services" },
  { value: "marketing", label: "Marketing & Advertising" },
  { value: "nonprofit", label: "Non-profit Organization" },
  { value: "government", label: "Government & Public Sector" },
  { value: "other", label: "Other" },
];

const COMPANY_SIZES = [
  { value: "under_10", label: "Under 10 employees" },
  { value: "10-50", label: "10-50 employees" },
  { value: "51-100", label: "51-100 employees" },
  { value: "101-200", label: "101-200 employees" },
  { value: "201-500", label: "201-500 employees" },
  { value: "500+", label: "500+ employees" },
];

function CompanyProfilePage() {
  const { user, isAuthenticated, loading: authLoading } = useAuth();
  const { t } = useLanguage();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [profile, setProfile] = useState(null);
  const [editMode, setEditMode] = useState(false);
  const [activeMenu, setActiveMenu] = useState("profile");

  // Sidebar menu for companies
  const SIDEBAR_MENU = [
    { id: "overview", icon: "📊", labelKey: "overview" },
    { id: "applications", icon: "📋", label: "Job Applications" },
    { id: "favorites", icon: "❤️", label: t("companyProfile.savedInterpreters") },
    { id: "alerts", icon: "🔔", labelKey: "alerts" },
    { id: "profile", icon: "🏢", label: t("companyProfile.title") },
    { id: "settings", icon: "⚙️", labelKey: "settings" },
  ];

  const [formData, setFormData] = useState({
    companyName: "",
    companySize: "",
    industry: "",
    description: "",
    website: "",
    headquarters: "",
    foundedYear: "",
    businessLicenseNumber: "",
  });

  const [businessLicenseFile, setBusinessLicenseFile] = useState(null);
  const [businessLicensePreview, setBusinessLicensePreview] = useState(null);
  const [logoFile, setLogoFile] = useState(null);
  const [logoPreview, setLogoPreview] = useState(null);
  const [uploadingLogo, setUploadingLogo] = useState(false);

  useEffect(() => {
    if (!authLoading && !isAuthenticated) {
      navigate(ROUTES.LOGIN);
    }
  }, [isAuthenticated, authLoading, navigate]);

  useEffect(() => {
    if (user?.role === "client") {
      fetchProfile();
    }
  }, [user]);

  const fetchProfile = async () => {
    try {
      setLoading(true);
      const response = await clientService.getProfile();
      setProfile(response.data);

      // Populate form
      setFormData({
        companyName: response.data.companyName || "",
        companySize: response.data.companySize || "",
        industry: response.data.industry || "",
        description: response.data.description || "",
        website: response.data.website || "",
        headquarters: response.data.headquarters || "",
        foundedYear: response.data.foundedYear || "",
        businessLicenseNumber: response.data.businessLicenseNumber || "",
      });

      if (response.data.businessLicense) {
        setBusinessLicensePreview(response.data.businessLicense);
      }

      // Load logo if exists
      if (response.data.logo) {
        setLogoPreview(response.data.logo);
      }
    } catch (error) {
      console.error("Error fetching profile:", error);
      toast.error("Failed to load profile");
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleBusinessLicenseChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      // Validate file type
      if (!file.type.match(/image\/(jpeg|jpg|png|pdf)/)) {
        toast.error("Please upload an image (JPEG, PNG) or PDF file");
        return;
      }

      // Validate file size (max 5MB)
      if (file.size > 5 * 1024 * 1024) {
        toast.error("File size must be less than 5MB");
        return;
      }

      setBusinessLicenseFile(file);

      // Create preview
      const reader = new FileReader();
      reader.onloadend = () => {
        setBusinessLicensePreview(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleLogoChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      // Validate file type - only images
      if (!file.type.match(/image\/(jpeg|jpg|png)/)) {
        toast.error("Please upload an image file (JPEG, PNG)");
        return;
      }

      // Validate file size (max 2MB for logo)
      if (file.size > 2 * 1024 * 1024) {
        toast.error("File size must be less than 2MB");
        return;
      }

      setLogoFile(file);

      // Create preview
      const reader = new FileReader();
      reader.onloadend = () => {
        setLogoPreview(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleUploadLogo = async () => {
    if (!logoFile) return;

    try {
      setUploadingLogo(true);
      const formData = new FormData();
      formData.append("logo", logoFile);

      await clientService.uploadLogo(formData);
      toast.success("Logo uploaded successfully");
      setLogoFile(null);
      fetchProfile();
    } catch (error) {
      console.error("Error uploading logo:", error);
      toast.error(error.response?.data?.message || "Failed to upload logo");
    } finally {
      setUploadingLogo(false);
    }
  };

  const handleSaveProfile = async () => {
    try {
      // Validate required fields
      if (
        !formData.companyName ||
        !formData.industry ||
        !formData.companySize ||
        !formData.description
      ) {
        toast.error(
          "Please fill in all required fields (Company Name, Industry, Size, Description)"
        );
        return;
      }

      setSaving(true);
      await clientService.updateProfile(formData);
      toast.success("Profile updated successfully");
      setEditMode(false);
      fetchProfile();
    } catch (error) {
      console.error("Error updating profile:", error);
      toast.error(error.response?.data?.message || "Failed to update profile");
    } finally {
      setSaving(false);
    }
  };

  const handleUploadBusinessLicense = async () => {
    try {
      if (!businessLicenseFile) {
        toast.error("Please select a business license file");
        return;
      }

      // Check if basic info is complete
      if (!profile.companyName || !profile.industry || !profile.companySize) {
        toast.error(
          "Please complete basic company information before uploading business license"
        );
        return;
      }

      setUploading(true);

      // Upload to cloudinary or your storage
      const uploadFormData = new FormData();
      uploadFormData.append("file", businessLicenseFile);
      uploadFormData.append("upload_preset", "gbridge_business_licenses"); // Configure in Cloudinary

      const uploadResponse = await fetch(
        `https://api.cloudinary.com/v1_1/${process.env.REACT_APP_CLOUDINARY_CLOUD_NAME}/image/upload`,
        {
          method: "POST",
          body: uploadFormData,
        }
      );

      const uploadData = await uploadResponse.json();

      // Save to backend
      await clientService.uploadBusinessLicense({
        businessLicenseUrl: uploadData.secure_url,
        businessLicenseNumber: formData.businessLicenseNumber,
      });

      toast.success(
        "Business license uploaded successfully! Your profile is now pending admin verification."
      );
      fetchProfile();
    } catch (error) {
      console.error("Error uploading business license:", error);
      toast.error("Failed to upload business license");
    } finally {
      setUploading(false);
    }
  };

  const getVerificationStatusBadge = () => {
    if (!profile) return null;

    const statusConfig = {
      unverified: {
        text: "Unverified",
        icon: "⚠️",
        className: styles.statusUnverified,
      },
      pending: {
        text: "Pending Verification",
        icon: "🕐",
        className: styles.statusPending,
      },
      verified: {
        text: "Verified",
        icon: "✓",
        className: styles.statusVerified,
      },
      rejected: {
        text: "Rejected",
        icon: "✕",
        className: styles.statusRejected,
      },
    };

    const status =
      statusConfig[profile.verificationStatus] || statusConfig.unverified;

    return (
      <div className={`${styles.statusBadge} ${status.className}`}>
        <span className={styles.statusIcon}>{status.icon}</span>
        <span className={styles.statusText}>{status.text}</span>
      </div>
    );
  };

  const isProfileComplete =
    profile?.companyName &&
    profile?.industry &&
    profile?.companySize &&
    profile?.description;
  const hasBusinessLicense = !!profile?.businessLicense;

  if (authLoading || loading) {
    return (
      <MainLayout>
        <div className={styles.loading}>Loading...</div>
      </MainLayout>
    );
  }

  if (user?.role !== "client") {
    return (
      <MainLayout>
        <div className={styles.error}>
          This page is only for company accounts
        </div>
      </MainLayout>
    );
  }

  return (
    <MainLayout>
      <div className={styles.dashboardRoot}>
        {/* Sidebar */}
        <aside className={styles.sidebar}>
          <div className={styles.sidebarHeader}>
            <h2 className={styles.sidebarTitle}>Dashboard</h2>
          </div>
          <nav className={styles.sidebarNav}>
            {SIDEBAR_MENU.map((item) => (
              <button
                key={item.id}
                className={`${styles.menuItem} ${
                  activeMenu === item.id ? styles.menuItemActive : ""
                }`}
                onClick={() => {
                  setActiveMenu(item.id);
                  if (item.id === "overview") {
                    navigate(ROUTES.DASHBOARD);
                  } else if (item.id === "applications") {
                    navigate(ROUTES.MY_APPLICATIONS);
                  } else if (item.id === "favorites") {
                    navigate(ROUTES.SAVED_JOBS);
                  } else if (item.id === "alerts") {
                    navigate(ROUTES.JOB_ALERTS);
                  } else if (item.id === "profile") {
                    navigate(ROUTES.COMPANY_PROFILE);
                  } else if (item.id === "settings") {
                    toast.info("Settings page coming soon!");
                  }
                }}
              >
                <span className={styles.menuIcon}>{item.icon}</span>
                <span className={styles.menuLabel}>
                  {item.label || t(`dashboard.${item.labelKey}`)}
                </span>
              </button>
            ))}
          </nav>
        </aside>

        {/* Main Content */}
        <main className={styles.mainContent}>
          <div className={styles.profileContainer}>
            <div className={styles.header}>
              <h1 className={styles.title}>{t("companyProfile.title")}</h1>
              {getVerificationStatusBadge()}
            </div>

            {/* Alert Messages */}
            {profile?.verificationStatus === "unverified" && (
              <div className={styles.alertWarning}>
                <span className={styles.alertIcon}>⚠️</span>
                <div className={styles.alertContent}>
                  <strong>{t("companyProfile.accountNotVerified")}</strong>
                  <p>{t("companyProfile.accountNotVerifiedMsg")}</p>
                </div>
              </div>
            )}

            {profile?.verificationStatus === "pending" && (
              <div className={styles.alertInfo}>
                <span className={styles.alertIcon}>🕐</span>
                <div className={styles.alertContent}>
                  <strong>{t("companyProfile.verificationPending")}</strong>
                  <p>{t("companyProfile.verificationPendingMsg")}</p>
                </div>
              </div>
            )}

            {profile?.verificationStatus === "rejected" &&
              profile?.verificationNote && (
                <div className={styles.alertDanger}>
                  <span className={styles.alertIcon}>✕</span>
                  <div className={styles.alertContent}>
                    <strong>{t("companyProfile.verificationRejected")}</strong>
                    <p>{profile.verificationNote}</p>
                    <p>{t("companyProfile.verificationRejectedMsg")}</p>
                  </div>
                </div>
              )}

            {/* Company Logo Section */}
            <div className={styles.section}>
              <div className={styles.sectionHeader}>
                <h2 className={styles.sectionTitle}>{t("companyProfile.companyLogo")}</h2>
              </div>

              <div className={styles.logoSection}>
                <div className={styles.logoDisplay}>
                  {logoPreview || profile?.logo ? (
                    <img
                      src={logoPreview || profile?.logo}
                      alt="Company Logo"
                      className={styles.logoImage}
                    />
                  ) : (
                    <div className={styles.logoPlaceholder}>
                      <span className={styles.logoIcon}>🏢</span>
                      <p>{t("companyProfile.noLogoUploaded")}</p>
                    </div>
                  )}
                </div>

                <div className={styles.logoUpload}>
                  <p className={styles.hint}>
                    {t("companyProfile.logoHint")}
                    <br />
                    {t("companyProfile.logoRecommendation")}
                  </p>

                  <div className={styles.uploadActions}>
                    <input
                      type="file"
                      id="companyLogo"
                      accept="image/jpeg,image/jpg,image/png"
                      onChange={handleLogoChange}
                      className={styles.fileInput}
                    />
                    <label
                      htmlFor="companyLogo"
                      className={styles.uploadBtn}
                    >
                      {logoPreview || profile?.logo ? t("companyProfile.changeLogo") : t("companyProfile.chooseLogo")}
                    </label>

                    {logoFile && (
                      <button
                        className={styles.submitBtn}
                        onClick={handleUploadLogo}
                        disabled={uploadingLogo}
                      >
                        {uploadingLogo ? t("companyProfile.uploading") : t("companyProfile.uploadLogo")}
                      </button>
                    )}
                  </div>
                </div>
              </div>
            </div>

            {/* Basic Information Section */}
            <div className={styles.section}>
              <div className={styles.sectionHeader}>
                <h2 className={styles.sectionTitle}>{t("companyProfile.basicInformation")}</h2>
                {!editMode && (
                  <button
                    className={styles.editBtn}
                    onClick={() => setEditMode(true)}
                  >
                    {t("companyProfile.edit")}
                  </button>
                )}
              </div>

              <div className={styles.formGrid}>
                <div className={styles.formGroup}>
                  <label className={styles.label}>
                    {t("companyProfile.companyName")} <span className={styles.required}>*</span>
                  </label>
                  {editMode ? (
                    <input
                      type="text"
                      name="companyName"
                      value={formData.companyName}
                      onChange={handleInputChange}
                      className={styles.input}
                      placeholder={t("companyProfile.enterCompanyName")}
                    />
                  ) : (
                    <p className={styles.value}>
                      {profile?.companyName || t("companyProfile.notProvided")}
                    </p>
                  )}
                </div>

                <div className={styles.formGroup}>
                  <label className={styles.label}>
                    {t("companyProfile.industry")} <span className={styles.required}>*</span>
                  </label>
                  {editMode ? (
                    <select
                      name="industry"
                      value={formData.industry}
                      onChange={handleInputChange}
                      className={styles.select}
                    >
                      <option value="">{t("companyProfile.selectIndustry")}</option>
                      {INDUSTRIES.map((ind) => (
                        <option key={ind.value} value={ind.value}>
                          {ind.label}
                        </option>
                      ))}
                    </select>
                  ) : (
                    <p className={styles.value}>
                      {INDUSTRIES.find((i) => i.value === profile?.industry)
                        ?.label || t("companyProfile.notProvided")}
                    </p>
                  )}
                </div>

                <div className={styles.formGroup}>
                  <label className={styles.label}>
                    {t("companyProfile.companySize")} <span className={styles.required}>*</span>
                  </label>
                  {editMode ? (
                    <select
                      name="companySize"
                      value={formData.companySize}
                      onChange={handleInputChange}
                      className={styles.select}
                    >
                      <option value="">{t("companyProfile.selectCompanySize")}</option>
                      {COMPANY_SIZES.map((size) => (
                        <option key={size.value} value={size.value}>
                          {size.label}
                        </option>
                      ))}
                    </select>
                  ) : (
                    <p className={styles.value}>
                      {COMPANY_SIZES.find(
                        (s) => s.value === profile?.companySize
                      )?.label || "Not provided"}
                    </p>
                  )}
                </div>

                <div className={styles.formGroup}>
                  <label className={styles.label}>Website</label>
                  {editMode ? (
                    <input
                      type="url"
                      name="website"
                      value={formData.website}
                      onChange={handleInputChange}
                      className={styles.input}
                      placeholder="https://example.com"
                    />
                  ) : (
                    <p className={styles.value}>
                      {profile?.website ? (
                        <a
                          href={profile.website}
                          target="_blank"
                          rel="noopener noreferrer"
                        >
                          {profile.website}
                        </a>
                      ) : (
                        "Not provided"
                      )}
                    </p>
                  )}
                </div>

                <div className={styles.formGroup}>
                  <label className={styles.label}>Headquarters</label>
                  {editMode ? (
                    <input
                      type="text"
                      name="headquarters"
                      value={formData.headquarters}
                      onChange={handleInputChange}
                      className={styles.input}
                      placeholder="City, Country"
                    />
                  ) : (
                    <p className={styles.value}>
                      {profile?.headquarters || "Not provided"}
                    </p>
                  )}
                </div>

                <div className={styles.formGroup}>
                  <label className={styles.label}>Founded Year</label>
                  {editMode ? (
                    <input
                      type="number"
                      name="foundedYear"
                      value={formData.foundedYear}
                      onChange={handleInputChange}
                      className={styles.input}
                      placeholder="2020"
                      min="1800"
                      max={new Date().getFullYear()}
                    />
                  ) : (
                    <p className={styles.value}>
                      {profile?.foundedYear || "Not provided"}
                    </p>
                  )}
                </div>

                <div className={`${styles.formGroup} ${styles.fullWidth}`}>
                  <label className={styles.label}>
                    Company Description{" "}
                    <span className={styles.required}>*</span>
                  </label>
                  {editMode ? (
                    <textarea
                      name="description"
                      value={formData.description}
                      onChange={handleInputChange}
                      className={styles.textarea}
                      placeholder="Brief introduction about your company..."
                      rows={4}
                    />
                  ) : (
                    <p className={styles.value}>
                      {profile?.description || "Not provided"}
                    </p>
                  )}
                </div>
              </div>

              {editMode && (
                <div className={styles.formActions}>
                  <button
                    className={styles.cancelBtn}
                    onClick={() => {
                      setEditMode(false);
                      // Reset form
                      setFormData({
                        companyName: profile?.companyName || "",
                        companySize: profile?.companySize || "",
                        industry: profile?.industry || "",
                        description: profile?.description || "",
                        website: profile?.website || "",
                        headquarters: profile?.headquarters || "",
                        foundedYear: profile?.foundedYear || "",
                        businessLicenseNumber:
                          profile?.businessLicenseNumber || "",
                      });
                    }}
                  >
                    Cancel
                  </button>
                  <button
                    className={styles.saveBtn}
                    onClick={handleSaveProfile}
                    disabled={saving}
                  >
                    {saving ? "Saving..." : "Save Changes"}
                  </button>
                </div>
              )}
            </div>

            {/* Business License Section */}
            <div className={styles.section}>
              <div className={styles.sectionHeader}>
                <h2 className={styles.sectionTitle}>
                  Business Registration Certificate
                  {!hasBusinessLicense && (
                    <span className={styles.required}>*</span>
                  )}
                </h2>
              </div>

              {!isProfileComplete && (
                <div className={styles.alertWarning}>
                  <span className={styles.alertIcon}>ℹ️</span>
                  <div className={styles.alertContent}>
                    <p>
                      Please complete basic company information before uploading
                      business license.
                    </p>
                  </div>
                </div>
              )}

              <div className={styles.licenseContainer}>
                <div className={styles.formGroup}>
                  <label className={styles.label}>
                    Business License Number
                  </label>
                  <input
                    type="text"
                    name="businessLicenseNumber"
                    value={formData.businessLicenseNumber}
                    onChange={handleInputChange}
                    className={styles.input}
                    placeholder="Enter business license number"
                    disabled={!isProfileComplete}
                    style={{ pointerEvents: 'auto' }}
                  />
                  <p className={styles.hint}>
                    Enter your official business registration number
                  </p>
                </div>

                <div className={styles.uploadSection}>
                  <label className={styles.label}>
                    Upload Business License (Scan/Photo - Color)
                  </label>
                  <p className={styles.hint}>
                    Please upload a clear color scan or photo of your business
                    registration certificate. Accepted formats: JPEG, PNG, PDF
                    (Max 5MB)
                  </p>

                  {businessLicensePreview && (
                    <div className={styles.preview}>
                      <img
                        src={businessLicensePreview}
                        alt="Business License"
                        className={styles.previewImage}
                      />
                      <button
                        className={styles.removePreviewBtn}
                        onClick={() => {
                          setBusinessLicenseFile(null);
                          setBusinessLicensePreview(profile?.businessLicense || null);
                        }}
                        title="Remove selected file"
                      >
                        ✕
                      </button>
                    </div>
                  )}

                  <div className={styles.uploadActions}>
                    <input
                      type="file"
                      id="businessLicense"
                      accept="image/jpeg,image/jpg,image/png,application/pdf"
                      onChange={handleBusinessLicenseChange}
                      className={styles.fileInput}
                      disabled={!isProfileComplete}
                    />
                    <label
                      htmlFor="businessLicense"
                      className={`${styles.uploadBtn} ${
                        !isProfileComplete ? styles.disabled : ""
                      }`}
                    >
                      {businessLicensePreview && !businessLicenseFile ? "Change File" : "Choose File"}
                    </label>

                    {businessLicenseFile && (
                      <button
                        className={styles.submitBtn}
                        onClick={handleUploadBusinessLicense}
                        disabled={uploading || !isProfileComplete}
                      >
                        {uploading ? "Uploading..." : "Submit for Verification"}
                      </button>
                    )}
                  </div>
                </div>
              </div>
            </div>

            {/* Verification Status Info */}
            {profile?.verificationStatus === "verified" && (
              <div className={styles.section}>
                <div className={styles.verifiedInfo}>
                  <span className={styles.verifiedIcon}>✓</span>
                  <div>
                    <h3>Company Verified</h3>
                    <p>
                      Your company has been verified on{" "}
                      {new Date(profile.verifiedAt).toLocaleDateString()}
                    </p>
                    <p className={styles.badgeInfo}>
                      A "Verified Company" badge will be displayed on all your
                      job postings.
                    </p>
                  </div>
                </div>
              </div>
            )}
          </div>
        </main>
      </div>
    </MainLayout>
  );
}

export default CompanyProfilePage;
